import{c as a,Z as i,Q as r,j as s,m as t,o}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Lexe Uses LDK to Run Self-Custodial Lightning in Secure Enclaves","description":"Learn how Lexe uses LDK to run self-custodial Lightning nodes inside Intel SGX secure enclaves with free, always-on node hosting","frontmatter":{"title":"Lexe Uses LDK to Run Self-Custodial Lightning in Secure Enclaves","description":"Learn how Lexe uses LDK to run self-custodial Lightning nodes inside Intel SGX secure enclaves with free, always-on node hosting","date":"2026-06-10","authors":["Max Fang"],"tags":["case-studies","self-custody","mobile","storage"]},"headers":[],"relativePath":"blog/lexe-uses-ldk-to-run-self-custodial-lightning-in-secure-enclaves.md","filePath":"blog/lexe-uses-ldk-to-run-self-custodial-lightning-in-secure-enclaves.md","lastUpdated":1781095283000}'),l={name:"blog/lexe-uses-ldk-to-run-self-custodial-lightning-in-secure-enclaves.md"};function c(h,e,d,u,g,p){const n=i("LexeArchitectureDiagram");return r(),s("div",null,[e[0]||(e[0]=t('<p><a href="https://lexe.app" target="_blank" rel="noreferrer">Lexe</a> is building the world&#39;s most cost-effective and reliable self-custodial Lightning nodes running inside secure hardware enclaves in the cloud. By leveraging the hardware-based isolation guarantees of Intel SGX, Lexe can offer a wallet that sends and receives payments 24/7 without retaining custody of users&#39; funds, as Lexe cannot read the keys inside of the enclaves.</p><p>Lexe wallet users enjoy reliable receives to BOLT 12 offers, Human Bitcoin Address (BIP 353), and Lightning Address, with always-on uptime for Nostr Wallet Connect. Lexe&#39;s TEE-based architecture also drastically reduces node hosting costs, allowing Lexe to offer enterprise-grade Lightning node hosting for free.</p><h1 id="the-challenge-secure-enclaves-are-highly-constrained" tabindex="-1">The Challenge: Secure Enclaves are Highly Constrained <a class="header-anchor" href="#the-challenge-secure-enclaves-are-highly-constrained" aria-label="Permalink to &quot;The Challenge: Secure Enclaves are Highly Constrained&quot;">​</a></h1><p>Secure enclaves (also called Trusted Execution Environments or TEEs) use hardware-based isolation to protect the programs running inside—server administrators cannot read the program memory or corrupt its execution. Among the available TEEs, we chose Intel SGX specifically for its minimal trusted computing base (TCB), which only includes the enclave application and the underlying hardware. In contrast, AWS Nitro, AMD SEV, and Intel TDX usually include an entire Linux kernel in their TCB, resulting in a significantly larger attack surface (an additional ~40 million lines of code which typically aren&#39;t hardened against malicious hypervisors).</p><p>Despite these security advantages, running Lightning inside enclaves comes with severe technical constraints. Lightning is a highly stateful protocol requiring constant peer communication, regular persistence of critical channel data, and blockchain monitoring. Enclaves have no direct access to filesystems, networking, or other standard OS facilities, meaning that the vast majority of existing applications simply will not run inside of an enclave.</p><p>To maintain the security boundary, all I/O must pass through carefully controlled interfaces. All persisted data must be encrypted and transmitted over a network, rather than written directly to disk. All communication between the enclave and the user&#39;s mobile client requires end-to-end encryption and protection against man-in-the-middle attacks, with TLS connections terminating inside the enclave itself.</p><h1 id="why-ldk-was-essential" tabindex="-1">Why LDK Was Essential <a class="header-anchor" href="#why-ldk-was-essential" aria-label="Permalink to &quot;Why LDK Was Essential&quot;">​</a></h1><p>Other Lightning implementations like LND or Core Lightning assume direct access to disk storage, network sockets, and system resources. They&#39;re designed as monolithic daemons that manage their own threads, persistence, and networking. While these implementations are well-suited for their target use cases, trying to retrofit them to run in an enclave would require extensive modifications that would be prohibitively difficult to maintain and audit.</p><p>LDK&#39;s highly modular approach, including the separation of Lightning protocol logic from all I/O operations, made it the only viable choice. LDK explicitly delegates these responsibilities to the host application through well-defined trait interfaces.</p><h1 id="lexe-s-architecture-with-ldk" tabindex="-1">Lexe&#39;s Architecture with LDK <a class="header-anchor" href="#lexe-s-architecture-with-ldk" aria-label="Permalink to &quot;Lexe&#39;s Architecture with LDK&quot;">​</a></h1>',10)),o(n),e[1]||(e[1]=t('<p>Our architecture leverages LDK&#39;s modularity in multiple places:</p><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>Since enclaves cannot access local disk directly, we implement custom logic within the <a href="https://docs.rs/lightning/0.1.5/lightning/chain/chainmonitor/trait.Persist.html" target="_blank" rel="noreferrer"><code>Persist</code></a> trait to encrypt node state and write it to remote storage via a network call. Because we persist over a network, we need async persistence; thankfully, LDK&#39;s persistence trait is runtime-agnostic, supporting both sync (blocking) and async (non-blocking) persistence implementations. Encrypting the node state ensures that even if an attacker compromises Lexe&#39;s infrastructure, they cannot read user secrets, only meaningless ciphertext.</p><h2 id="chain-interface" tabindex="-1">Chain Interface <a class="header-anchor" href="#chain-interface" aria-label="Permalink to &quot;Chain Interface&quot;">​</a></h2><p>Since <code>bitcoind</code> cannot run inside an enclave, we need another way to get blockchain data. While other Lightning implementations require block-based synchronization from a full node or SPV client, LDK allows transaction-based synchronization via the <a href="https://docs.rs/lightning/0.1.5/lightning/chain/trait.Confirm.html" target="_blank" rel="noreferrer"><code>Confirm</code></a> trait, along with a ready-to-use Esplora client implementation via the <a href="https://docs.rs/lightning-transaction-sync" target="_blank" rel="noreferrer"><code>lightning-transaction-sync</code></a> crate. This transaction-based approach is very efficient—instead of every Lexe user node processing the entirety of every block, each node syncs only the specific transactions relevant to its channels and on-chain wallet.</p><h2 id="shared-components" tabindex="-1">Shared Components <a class="header-anchor" href="#shared-components" aria-label="Permalink to &quot;Shared Components&quot;">​</a></h2><p>Enclaves have the particular requirement that all memory used by the node must be allocated up-front. Simultaneously, we want to do payment routing <em>inside</em> the enclave, in order to preserve user privacy. Normally, this would require each user node to maintain its own copy of the entire network graph and route scorer, which can easily exceed 400 MiB of RAM, meaning we have to allocate at least 500 MiB (or more!) per user, which would be prohibitively expensive for thousands of concurrent users.</p><p>Instead, we adopted what we call our &quot;meganode&quot; architecture: running hundreds of user nodes per enclave process instead of just one. LDK makes this possible by letting us share the <a href="https://docs.rs/lightning/0.1.5/lightning/routing/gossip/struct.NetworkGraph.html" target="_blank" rel="noreferrer"><code>NetworkGraph</code></a> and <a href="https://docs.rs/lightning/0.1.5/lightning/routing/scoring/struct.ProbabilisticScorer.html" target="_blank" rel="noreferrer"><code>ProbabilisticScorer</code></a> (which don&#39;t contain sensitive data) across all user nodes, while keeping each user&#39;s keys and channel state completely isolated. The result is a 10-100x improvement in per-user memory requirements.</p><h1 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h1><p>LDK&#39;s modularity enabled us to achieve what seemed impossible: running Lightning nodes inside SGX enclaves.</p><p>Users maintain full custody while their nodes run 24/7 in our infrastructure, finally solving Lightning&#39;s offline receive problem. SGX&#39;s hardware isolation prevents even Lexe from accessing user funds, while remote attestation and reproducible builds let users verify the exact code running on their behalf.</p><p>Lexe&#39;s meganode architecture delivers 10-100x memory efficiency by sharing the network graph and other non-sensitive components across users. This dramatic reduction in resource consumption enables free node hosting with sustainable economics.</p><p>Users can send and receive payments 24/7 without managing any infrastructure. Developers integrate Lightning through our SDK without the operational burden of node management, uptime, or channel maintenance.</p><p>LDK&#39;s flexibility let us solve what seemed impossible: running Lightning in a secure enclave with no filesystem, no direct networking, and fixed memory allocation. The same modularity that enabled our unusual architecture will enable others—Lightning on embedded devices, hardware wallets, or environments we haven&#39;t yet imagined. By solving the Lightning trilemma—delivering self-custody, convenience, and low cost all at once—we can finally build Lightning wallets that just work.</p><h1 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h1><ul><li><a href="https://lexe.app" target="_blank" rel="noreferrer">Lexe Wallet</a></li><li><a href="https://github.com/lexe-app/lexe-sidecar-sdk" target="_blank" rel="noreferrer">Lexe Sidecar SDK</a></li><li><a href="https://github.com/lexe-app/lexe-public/blob/master/SECURITY.md" target="_blank" rel="noreferrer">Lexe&#39;s security model in detail</a></li><li><a href="https://github.com/lexe-app/lexe-public" target="_blank" rel="noreferrer">Lexe monorepo</a></li></ul>',16))])}const y=a(l,[["render",c]]);export{f as __pageData,y as default};
